32	static std::string make_border(const std::string& text)
33	{
34	    std::stringstream ss;
35	    ss << boost::format("  _____________________________________________________")
36	       << std::endl;
37	    ss << boost::format(" /") << std::endl;
38	    std::vector<std::string> lines;
39	    boost::split(lines, text, boost::is_any_of("\n"));
40	    while (lines.back().empty())
41	        lines.pop_back(); // strip trailing newlines
42	    if (!lines.empty())
43	        lines[0] = "    " + lines[0]; // indent the title line
