356	void run_interactive_regs_shell(rfnoc::noc_block_base::sptr blk_ctrl)
357	{
358	    std::cout << "<<< Interactive Block Peeker/Poker >>>" << std::endl;
359	    std::cout << "Type 'help' to get a list of commands." << std::endl;
360	    while (true) {
361	        std::string input;
362	        std::cout << ">>> " << std::flush;
363	        std::getline(std::cin, input);
364	        std::stringstream ss(input);
365	        std::string command;
366	        ss >> command;
367	        if (command == "poke32") {
368	            std::string addr_s, data_s;
369	            uint32_t addr, data;
370	            try {
371	                ss >> addr_s >> data_s;
372	                addr = str2uint32(addr_s);
373	                data = str2uint32(data_s);
374	            } catch (std::exception&) {
375	                std::cout << "Usage: poke32 $addr $data" << std::endl;
376	                continue;
377	            }
378	            blk_ctrl->regs().poke32(addr, data);
379	        }
380	        if (command == "peek32") {
