405	int UHD_SAFE_MAIN(int argc, char* argv[])
406	{
407	    po::options_description desc("Allowed options");
408	    // clang-format off
409	    desc.add_options()
410	        ("help", "help message")
411	        ("version", "print the version string and exit")
412	        ("args", po::value<std::string>()->default_value(""), "device address args")
413	        ("tree", "specify to print a complete property tree")
414	        ("string", po::value<std::string>(), "query a string value from the property tree")
415	        ("double", po::value<std::string>(), "query a double precision floating point value from the property tree")
416	        ("int", po::value<std::string>(), "query a integer value from the property tree")
417	        ("sensor", po::value<std::string>(), "query a sensor value from the property tree")
418	        ("range", po::value<std::string>(), "query a range (gain, bandwidth, frequency, ...)  from the property tree")
419	        ("vector", "when querying a string, interpret that as std::vector")
420	        ("init-only", "skip all queries, only initialize device")
421	        ("interactive-reg-iface", po::value<std::string>(), "RFNoC devices only: Spawn a shell to interactively peek and poke registers on RFNoC blocks")
422	    ;
423	    // clang-format on
424	
425	    po::variables_map vm;
426	    po::store(po::parse_command_line(argc, argv, desc), vm);
427	    po::notify(vm);
428	
429	    // print the help message
430	    if (vm.count("help")) {
431	        std::cout << boost::format("UHD USRP Probe %s") % desc << std::endl;
432	        return EXIT_FAILURE;
433	    }
434	
435	    if (vm.count("version")) {
436	        std::cout << uhd::get_version_string() << std::endl;
437	        return EXIT_SUCCESS;
438	    }
439	
440	    device::sptr dev         = device::make(vm["args"].as<std::string>());
441	    property_tree::sptr tree = dev->get_tree();
442	    rfnoc::rfnoc_graph::sptr graph;
443	    try {
444	        graph = rfnoc::rfnoc_graph::make(vm["args"].as<std::string>());
445	    } catch (uhd::key_error&) {
446	        // pass
447	    }
448	
449	    if (vm.count("string")) {
450	        if (vm.count("vector")) {
451	            std::vector<std::string> str_vector =
452	                tree->access<std::vector<std::string>>(vm["string"].as<std::string>())
453	                    .get();
454	            std::cout << "(";
455	            for (const std::string& str : str_vector) {
456	                std::cout << str << ",";
457	            }
458	            std::cout << ")" << std::endl;
459	        } else {
460	            std::cout << tree->access<std::string>(vm["string"].as<std::string>()).get()
461	                      << std::endl;
462	        }
463	        return EXIT_SUCCESS;
464	    }
465	
466	    if (vm.count("double")) {
467	        std::cout << tree->access<double>(vm["double"].as<std::string>()).get()
468	                  << std::endl;
469	        return EXIT_SUCCESS;
470	    }
471	
472	    if (vm.count("int")) {
473	        std::cout << tree->access<int>(vm["int"].as<std::string>()).get() << std::endl;
474	        return EXIT_SUCCESS;
475	    }
476	
477	    if (vm.count("sensor")) {
478	        std::cout << tree->access<uhd::sensor_value_t>(vm["sensor"].as<std::string>())
479	                         .get()
480	                         .value
481	                  << std::endl;
482	        return EXIT_SUCCESS;
483	    }
484	
485	    if (vm.count("range")) {
486	        meta_range_t range =
487	            tree->access<meta_range_t>(vm["range"].as<std::string>()).get();
488	        std::cout << boost::format("%.1f:%.1f:%.1f") % range.start() % range.step()
489	                         % range.stop()
490	                  << std::endl;
491	        return EXIT_SUCCESS;
492	    }
493	
494	    if (vm.count("interactive-reg-iface")) {
495	        if (!graph) {
496	            std::cout << "ERROR: --interactive-reg-iface requires an RFNoC device!"
497	                      << std::endl;
498	            return EXIT_FAILURE;
499	        }
500	        const rfnoc::block_id_t block_id(vm["interactive-reg-iface"].as<std::string>());
501	        auto block_ctrl = graph->get_block(block_id);
502	        run_interactive_regs_shell(block_ctrl);
503	        return EXIT_SUCCESS;
504	    }
505	
506	    if (vm.count("tree") != 0) {
507	        print_tree("/", tree);
508	    } else if (not vm.count("init-only")) {
509	        std::string device_pp_string = get_device_pp_string(tree);
510	        if (graph) {
511	            device_pp_string += get_rfnoc_pp_string(graph, tree);
512	        }
513	        std::cout << make_border(device_pp_string) << std::endl;
514	    }
515	
516	    return EXIT_SUCCESS;
517	}
